import yaml
import re
from dataclasses import dataclass, field
from typing import Dict, List, Optional
from pathlib import Path
from urllib.parse import urlparse

@dataclass
class ModelConfig:
    name: str = "gemma2:2b"
    base_url: str = "http://localhost:11434"
    temperature: float = 0.1
    max_tokens: int = 4096

@dataclass
class BashConfig:
    allowed_commands: List[str] = field(default_factory=lambda: [
        "git", "npm", "pip", "python", "python3", "node", "cargo", "go", "make", "docker", "ls", "pwd", "whoami", "date", "cat", "head", "tail", "grep", "find", "mkdir", "touch", "cp", "mv", "rm"
    ])
    timeout: int = 30

@dataclass
class ToolsConfig:
    enabled: List[str] = field(default_factory=lambda: [
        "file_read", "file_write", "file_edit", "bash_execute", "grep_search", "git_operations"
    ])
    bash: BashConfig = field(default_factory=BashConfig)
    safe_workdir: str = "/home/commander/Desktop/BackupOpencode"
    allow_outside_workdir: bool = False

@dataclass
class InterfaceConfig:
    interactive_mode: bool = True
    syntax_highlighting: bool = True
    auto_save: bool = False
    confirm_destructive: bool = True
    compact_mode: bool = True
    auto_model_selection: bool = False  # Set to true for kiosk mode
    default_mode: str = "auto"  # fast|auto|think|smart
    auto_suggest_tools: bool = False  # Suggest save/run when strong indicators exist

@dataclass
class HistoryConfig:
    max_entries: int = 100
    save_to_file: bool = True
    file_path: str = ".opencode_history"
    resume_last_session: bool = True

@dataclass
class RoutingConfig:
    """Configuration for intelligent routing system"""
    enabled: bool = True
    structured_threshold: float = 0.7
    reasoning_threshold: float = 0.6
    continuation_threshold: float = 0.8
    recall_threshold: float = 0.8
    tool_threshold: float = 0.7
    # Recall gating using context scoring/memory presence
    memory_gate_min_score: float = 0.6
    summary_gate_min_score: float = 0.5
    lane_timeouts: Dict[str, int] = field(default_factory=lambda: {
        'standard': 12,
        'deliberate': 25,
        'recall': 5,
        'tool_use': 15
    })
    performance_targets: Dict[str, float] = field(default_factory=lambda: {
        'structured': 90.0,
        'recall': 95.0,
        'general': 80.0
    })
    use_mvco_router: bool = True

@dataclass
class OptimizationConfig:
    """Configuration for model optimization and context management"""
    enabled: bool = True
    context_scoring: bool = True
    dynamic_pruning: bool = True
    adaptive_timeouts: bool = True
    max_context_tokens: int = 2000
    pruning_ratio: float = 0.8  # Can prune up to 80% of context
    performance_monitoring: bool = True

@dataclass
class RuntimeConfig:
    """Configuration for runtime resource management"""
    resources: int = 50  # Resource level percentage (25, 50, 75, 100)
    auto_detect: bool = True  # Auto-detect appropriate resource level
    cpu_threads: Optional[int] = None  # Override CPU threads (None = auto)
    gpu_enabled: bool = False  # Enable GPU acceleration when available
    max_memory_mb: Optional[int] = None  # Override memory limit (None = auto)
    slice_generation: bool = True  # Enable time-sliced generation
    fallback_model: str = "gemma2:2b-16k"  # Safe fallback model

@dataclass
class QualityRecoveryConfig:
    """Configuration for the Quality Recovery System"""
    enabled: bool = True
    instant_hooks_enabled: bool = True
    rag_feedback_enabled: bool = True
    observer_pattern_enabled: bool = True
    mode: str = "balanced"  # performance_first, balanced, feature_rich, learning
    # Legacy alias (do not use in code; only for migration)
    mvco_enabled: bool | None = None

@dataclass
class PolicyConfig:
    """Configuration for the generation policy provider."""
    enabled: bool = True
    provider: str = "basic"  # basic, advanced
    allow_options_override: bool = True
    caps_fast: Dict[str, int] = field(default_factory=lambda: {
        'standard': 120, 'structured': 90, 'reasoning': 200
    })
    caps_auto: Dict[str, int] = field(default_factory=lambda: {
        'standard': 300, 'structured': 220, 'reasoning': 450
    })
    caps_think: Dict[str, int] = field(default_factory=lambda: {
        'standard': 600, 'structured': 350, 'reasoning': 900
    })

@dataclass
class AgenticConfig:
    """Configuration for the Agentic Project System"""
    enabled: bool = True
    confirmation_level: str = "MODERATE"  # NONE, CRITICAL, MODERATE, DETAILED
    resource_constraints: str = "STANDARD"  # MINIMAL, LIMITED, STANDARD, ABUNDANT
    auto_handoff_enabled: bool = False

@dataclass
class Config:
    model: ModelConfig = field(default_factory=ModelConfig)
    system_prompt: str = """You are OpenCode, an AI-powered code assistant. You help users with software development tasks including:
- Code generation and refactoring
- Bug fixes and debugging
- Code analysis and explanation
- Project structure understanding
- File operations and editing

You have access to various tools to interact with the file system, execute commands, and search code.
Be concise, accurate, and helpful. Always consider security best practices."""
    tools: ToolsConfig = field(default_factory=ToolsConfig)
    interface: InterfaceConfig = field(default_factory=InterfaceConfig)
    history: HistoryConfig = field(default_factory=HistoryConfig)
    routing: RoutingConfig = field(default_factory=RoutingConfig)
    optimization: OptimizationConfig = field(default_factory=OptimizationConfig)
    runtime: RuntimeConfig = field(default_factory=RuntimeConfig)
    quality_recovery: QualityRecoveryConfig = field(default_factory=QualityRecoveryConfig)
    agentic: AgenticConfig = field(default_factory=AgenticConfig)
    policy: PolicyConfig = field(default_factory=PolicyConfig)
    config_path: Optional[str] = None

    @classmethod
    def load(cls, config_path: str) -> 'Config':
        """Load configuration from YAML file"""
        path = Path(config_path)
        if not path.exists():
            raise FileNotFoundError(f"Config file not found: {config_path}")
        
        with open(path, 'r') as f:
            data = yaml.safe_load(f)
        
        config = cls.from_dict(data)
        config.config_path = config_path

        # Validate configuration
        config.validate_and_raise()

        return config
    
    @classmethod
    def from_dict(cls, data: Dict) -> 'Config':
        """Create Config from dictionary"""
        config = cls()
        
        if 'model' in data:
            model_data = data['model']
            config.model = ModelConfig(
                name=model_data.get('name', ModelConfig().name),
                base_url=model_data.get('base_url', ModelConfig().base_url),
                temperature=model_data.get('temperature', ModelConfig().temperature),
                max_tokens=model_data.get('max_tokens', ModelConfig().max_tokens)
            )
        
        if 'system_prompt' in data:
            config.system_prompt = data['system_prompt']
        
        if 'tools' in data:
            tools_data = data['tools']
            bash_config = BashConfig()
            if 'bash' in tools_data:
                bash_data = tools_data['bash']
                bash_config.allowed_commands = bash_data.get('allowed_commands', bash_config.allowed_commands)
                bash_config.timeout = bash_data.get('timeout', bash_config.timeout)
            
            config.tools = ToolsConfig(
                enabled=tools_data.get('enabled', ToolsConfig().enabled),
                bash=bash_config
            )
        
        if 'interface' in data:
            interface_data = data['interface']
            config.interface = InterfaceConfig(
                interactive_mode=interface_data.get('interactive_mode', InterfaceConfig().interactive_mode),
                syntax_highlighting=interface_data.get('syntax_highlighting', InterfaceConfig().syntax_highlighting),
                auto_save=interface_data.get('auto_save', InterfaceConfig().auto_save),
                confirm_destructive=interface_data.get('confirm_destructive', InterfaceConfig().confirm_destructive),
                compact_mode=interface_data.get('compact_mode', InterfaceConfig().compact_mode),
                auto_model_selection=interface_data.get('auto_model_selection', InterfaceConfig().auto_model_selection),
                default_mode=interface_data.get('default_mode', InterfaceConfig().default_mode),
                auto_suggest_tools=interface_data.get('auto_suggest_tools', InterfaceConfig().auto_suggest_tools),
            )
        
        if 'history' in data:
            history_data = data['history']
            config.history = HistoryConfig(
                max_entries=history_data.get('max_entries', HistoryConfig().max_entries),
                save_to_file=history_data.get('save_to_file', HistoryConfig().save_to_file),
                file_path=history_data.get('file_path', HistoryConfig().file_path),
                resume_last_session=history_data.get('resume_last_session', HistoryConfig().resume_last_session),
            )

        if 'routing' in data:
            routing_data = data['routing']
            config.routing = RoutingConfig(
                enabled=routing_data.get('enabled', RoutingConfig().enabled),
                structured_threshold=routing_data.get('structured_threshold', RoutingConfig().structured_threshold),
                reasoning_threshold=routing_data.get('reasoning_threshold', RoutingConfig().reasoning_threshold),
                continuation_threshold=routing_data.get('continuation_threshold', RoutingConfig().continuation_threshold),
                recall_threshold=routing_data.get('recall_threshold', RoutingConfig().recall_threshold),
                tool_threshold=routing_data.get('tool_threshold', RoutingConfig().tool_threshold),
                lane_timeouts=routing_data.get('lane_timeouts', RoutingConfig().lane_timeouts),
                performance_targets=routing_data.get('performance_targets', RoutingConfig().performance_targets),
                use_mvco_router=routing_data.get('use_mvco_router', RoutingConfig().use_mvco_router),
                memory_gate_min_score=routing_data.get('memory_gate_min_score', RoutingConfig().memory_gate_min_score),
                summary_gate_min_score=routing_data.get('summary_gate_min_score', RoutingConfig().summary_gate_min_score),
            )

        if 'optimization' in data:
            opt_data = data['optimization']
            config.optimization = OptimizationConfig(
                enabled=opt_data.get('enabled', OptimizationConfig().enabled),
                context_scoring=opt_data.get('context_scoring', OptimizationConfig().context_scoring),
                dynamic_pruning=opt_data.get('dynamic_pruning', OptimizationConfig().dynamic_pruning),
                adaptive_timeouts=opt_data.get('adaptive_timeouts', OptimizationConfig().adaptive_timeouts),
                max_context_tokens=opt_data.get('max_context_tokens', OptimizationConfig().max_context_tokens),
                pruning_ratio=opt_data.get('pruning_ratio', OptimizationConfig().pruning_ratio),
                performance_monitoring=opt_data.get('performance_monitoring', OptimizationConfig().performance_monitoring)
            )

        if 'runtime' in data:
            runtime_data = data['runtime']
            config.runtime = RuntimeConfig(
                resources=runtime_data.get('resources', RuntimeConfig().resources),
                auto_detect=runtime_data.get('auto_detect', RuntimeConfig().auto_detect),
                cpu_threads=runtime_data.get('cpu_threads', RuntimeConfig().cpu_threads),
                gpu_enabled=runtime_data.get('gpu_enabled', RuntimeConfig().gpu_enabled),
                max_memory_mb=runtime_data.get('max_memory_mb', RuntimeConfig().max_memory_mb),
                slice_generation=runtime_data.get('slice_generation', RuntimeConfig().slice_generation),
                fallback_model=runtime_data.get('fallback_model', RuntimeConfig().fallback_model)
            )

        if 'quality_recovery' in data:
            qr_data = data['quality_recovery']

            # Migrate legacy 'mvco_enabled' → 'routing.use_mvco_router'
            routing_data = data.get('routing', {})
            if 'mvco_enabled' in qr_data and 'use_mvco_router' not in routing_data:
                routing_data['use_mvco_router'] = bool(qr_data['mvco_enabled'])
                data['routing'] = routing_data

            config.quality_recovery = QualityRecoveryConfig(
                enabled=qr_data.get('enabled', QualityRecoveryConfig().enabled),
                instant_hooks_enabled=qr_data.get('instant_hooks_enabled', QualityRecoveryConfig().instant_hooks_enabled),
                rag_feedback_enabled=qr_data.get('rag_feedback_enabled', QualityRecoveryConfig().rag_feedback_enabled),
                observer_pattern_enabled=qr_data.get('observer_pattern_enabled', QualityRecoveryConfig().observer_pattern_enabled),
                mode=qr_data.get('mode', QualityRecoveryConfig().mode)
            )

        if 'policy' in data:
            pol = data['policy']
            config.policy = PolicyConfig(
                enabled=pol.get('enabled', PolicyConfig().enabled),
                provider=pol.get('provider', PolicyConfig().provider),
                allow_options_override=pol.get('allow_options_override', PolicyConfig().allow_options_override),
                caps_fast=pol.get('caps_fast', PolicyConfig().caps_fast),
                caps_auto=pol.get('caps_auto', PolicyConfig().caps_auto),
                caps_think=pol.get('caps_think', PolicyConfig().caps_think),
            )

        if 'agentic' in data:
            agentic_data = data['agentic']
            config.agentic = AgenticConfig(
                enabled=agentic_data.get('enabled', AgenticConfig().enabled),
                confirmation_level=agentic_data.get('confirmation_level', AgenticConfig().confirmation_level),
                resource_constraints=agentic_data.get('resource_constraints', AgenticConfig().resource_constraints),
                auto_handoff_enabled=agentic_data.get('auto_handoff_enabled', AgenticConfig().auto_handoff_enabled)
            )

        return config
    
    @classmethod
    def default(cls) -> 'Config':
        """Return default configuration"""
        return cls()
    
